const clientId = $input.first().json.clientId;
const redirectUri = $input.first().json.redirectUri;
const tenantId = $input.first().json.tenantId;
const scopes = $input.first().json.scopes;
const state = $input.first().json.state;
const domainHint = $input.first().json.domainHint || 'organizations';
const promptType = $input.first().json.promptType || 'none';

// Build base OAuth URL
let oauthUrl = `https://login.microsoftonline.com/${tenantId}/oauth2/v2.0/authorize?` +
  `client_id=${encodeURIComponent(clientId)}&` +
  `response_type=code&` +
  `redirect_uri=${encodeURIComponent(redirectUri)}&` +
  `response_mode=query&` +
  `scope=${encodeURIComponent(scopes)}&` +
  `state=${encodeURIComponent(state)}`;

// Add domain_hint to skip account type selection
if (domainHint) {
  oauthUrl += `&domain_hint=${domainHint}`;
}

// Add prompt parameter only if not 'none'
// 'none' = SSO (best UX), will fail gracefully if user not logged in
if (promptType && promptType !== 'none') {
  oauthUrl += `&prompt=${promptType}`;
}

console.log('✅ OAuth URL generated with prompt:', promptType);

return {
  json: {
    oauthUrl: oauthUrl,
    promptType: promptType,
    domainHint: domainHint
  }
};

const crypto = require('crypto');

// Access input from previous node
const inputData = $input.first().json;

// Generate secure CSRF token (32 bytes = 256 bits)
const csrfToken = crypto.randomBytes(32).toString('base64url');

// Generate unique session ID
const sessionId = `${Date.now()}_${crypto.randomBytes(4).toString('hex')}`;

// Create state object with additional security metadata
const stateData = {
    csrf: csrfToken,
    timestamp: String(Math.floor(Date.now() / 1000)),
    sessionId: sessionId,
    nonce: crypto.randomBytes(16).toString('base64url')
};

// Encode state as base64url JSON
const stateJson = JSON.stringify(stateData);
const stateEncoded = Buffer.from(stateJson).toString('base64url');

console.log(`✅ Generated sessionId: ${sessionId}`);
console.log(`✅ CSRF token: ${csrfToken.substring(0, 10)}...`);
console.log(`✅ State encoded: ${stateEncoded.substring(0, 20)}...`);

// Return all config fields + encoded state
return [{
    json: {
        clientId: inputData.clientId,
        redirectUri: inputData.redirectUri,
        tenantId: inputData.tenantId,
        scopes: inputData.scopes,
        state: stateEncoded,
        sessionId: sessionId,
        csrfToken: csrfToken,
        domainHint: inputData.domainHint || 'organizations',
        promptType: inputData.promptType || 'none'
    }
}];

